sqlite:     SELECT "from" AS col_name, "table" AS tab_ref, "to" AS col_ref, 'FK_' || seq AS name FROM pragma_foreign_key_list('{tab_name}');
duckdb:     SELECT kcu.column_name AS col_name, ccu.table_name AS tab_ref, ccu.column_name AS col_ref, tc.constraint_name AS name FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON tc.constraint_name = kcu.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name = tc.constraint_name WHERE tc.table_name = '{tab_name}' AND tc.constraint_type = 'FOREIGN KEY';
postgresql: SELECT kcu.column_name as col_name, ccu.table_name as tab_ref, ccu.column_name as col_ref, tc.constraint_name as name FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON tc.constraint_name = kcu.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name = tc.constraint_name WHERE tc.table_name = '{tab_name}' AND tc.constraint_type = 'FOREIGN KEY';
mysql:      SELECT COLUMN_NAME as col_name, REFERENCED_TABLE_NAME as tab_ref, REFERENCED_COLUMN_NAME as col_ref, CONSTRAINT_NAME as name FROM information_schema.KEY_COLUMN_USAGE WHERE TABLE_NAME = '{tab_name}' AND REFERENCED_TABLE_NAME IS NOT NULL;
mssql:      SELECT COL_NAME(fkc.parent_object_id, fkc.parent_column_id) AS col_name, OBJECT_NAME(fkc.referenced_object_id) AS tab_ref, COL_NAME(fkc.referenced_object_id, fkc.referenced_column_id) AS col_ref, fk.name AS name FROM sys.foreign_keys fk JOIN sys.foreign_key_columns fkc ON fk.object_id = fkc.constraint_object_id WHERE OBJECT_NAME(fk.parent_object_id) = '{tab_name}';
oracle:     SELECT cc.COLUMN_NAME AS col_name, rc.TABLE_NAME AS tab_ref, rc.COLUMN_NAME AS col_ref, c.CONSTRAINT_NAME AS name FROM USER_CONSTRAINTS c JOIN USER_CONS_COLUMNS cc ON c.CONSTRAINT_NAME = cc.CONSTRAINT_NAME JOIN USER_CONS_COLUMNS rc ON c.R_CONSTRAINT_NAME = rc.CONSTRAINT_NAME WHERE c.TABLE_NAME = UPPER('{tab_name}') AND c.CONSTRAINT_TYPE = 'R' AND cc.POSITION = rc.POSITION;
starrocks:  SELECT NULL AS col_name, NULL AS tab_ref, NULL AS col_ref, NULL AS name WHERE 1=0;
hive:       SELECT NULL AS col_name, NULL AS tab_ref, NULL AS col_ref, NULL AS name FROM (SELECT 1 AS x) t WHERE 1=0;
trino:      SELECT kcu.column_name AS col_name, ccu.table_name AS tab_ref, ccu.column_name AS col_ref, tc.constraint_name AS name FROM information_schema.table_constraints tc JOIN information_schema.key_column_usage kcu ON tc.constraint_name = kcu.constraint_name JOIN information_schema.constraint_column_usage ccu ON ccu.constraint_name = tc.constraint_name WHERE tc.table_name = '{tab_name}' AND tc.constraint_type = 'FOREIGN KEY';